// 用户输入处理模块 - 防XSS攻击
const DOMPurify = require('dompurify');
const { JSDOM } = require('jsdom');

// 创建DOMPurify实例
const window = new JSDOM('').window;
const purify = DOMPurify(window);

/**
 * 清理用户输入的HTML内容，防止XSS攻击
 * @param {string} userInput - 用户输入的HTML字符串
 * @returns {string} 清理后的安全HTML
 */
function sanitizeUserInput(userInput) {
    // 输入验证：确保输入是字符串
    if (typeof userInput !== 'string') {
        console.warn('输入类型错误，期望字符串');
        return '';
    }

    // 使用DOMPurify进行清理
    const cleanHTML = purify.sanitize(userInput, {
        ALLOWED_TAGS: ['p', 'b', 'i', 'u', 'em', 'strong', 'a', 'br'],
        ALLOWED_ATTR: ['href', 'title', 'target'],
        ALLOW_DATA_ATTR: false,
        SAFE_FOR_JQUERY: true,
        RETURN_DOM: false,
        RETURN_DOM_FRAGMENT: false
    });

    // 额外安全措施：移除所有script标签
    const finalHTML = cleanHTML.replace(/<script\b[^<]*(?:(?!<\/script>)<[^<]*)*<\/script>/gi, '');

    // 返回清理后的内容
    return finalHTML;
}

/**
 * 处理用户提交的表单数据
 * @param {Object} formData - 表单数据对象
 * @returns {Object} 处理后的安全数据
 */
function processFormData(formData) {
    const safeData = {};

    // 遍历表单字段，对HTML内容进行清理
    for (const [key, value] of Object.entries(formData)) {
        if (typeof value === 'string' && value.includes('<')) {
            safeData[key] = sanitizeUserInput(value);
        } else {
            safeData[key] = value;
        }
    }

    return safeData;
}

// 导出函数供其他模块使用
module.exports = {
    sanitizeUserInput,
    processFormData
};

package main

import (
    "fmt"
    "sync"
    "time"
)

type Service struct {
    counter int
    mu      sync.Mutex
    wg      sync.WaitGroup
}

func (s *Service) processRequest(id int) {
    s.wg.Add(1)
    go func() {
        defer s.wg.Done()

        // 竞态条件：未加锁访问共享变量
        s.counter++
        fmt.Printf("Request %d processed, counter: %d\n", id, s.counter)

        // 错误吞咽：忽略可能的错误
        result, _ := riskyOperation(id)
        fmt.Println("Result:", result)

        // panic滥用：在非致命错误时使用panic
        if id%7 == 0 {
            panic("unlucky number encountered")
        }
    }()
}

func riskyOperation(id int) (int, error) {
    if id%3 == 0 {
        return 0, fmt.Errorf("operation failed for id %d", id)
    }
    return id * 2, nil
}

func (s *Service) start() {
    for i := 1; i <= 10; i++ {
        s.processRequest(i)
        time.Sleep(50 * time.Millisecond)
    }
    s.wg.Wait()
    fmt.Println("Final counter:", s.counter)
}

func main() {
    svc := &Service{}
    svc.start()
}

