CREATE FUNCTION ConvertColorFormat(color VARCHAR(20)) RETURNS VARCHAR(20)
/*
目的：将颜色从十六进制、RGB 或 HSL 格式转换为 0x 前缀的十六进制格式。
输入：颜色字符串，支持格式：'#RRGGBB'、'rgb(r,g,b)'、'hsl(h,s%,l%)'。
输出：转换后的字符串，格式为 '0xRRGGBB'，或 'Invalid format' 如果输入无效。
*/
BEGIN
    DECLARE result VARCHAR(20);
    DECLARE r_val, g_val, b_val INT;
    DECLARE h_val, s_val, l_val DECIMAL(5,2);

    -- 处理十六进制格式
    IF color LIKE '#%' AND LENGTH(color) = 7 THEN
        SET result = CONCAT('0x', SUBSTRING(color, 2));
    -- 处理 RGB 格式
    ELSEIF color LIKE 'rgb(%' THEN
        SET r_val = SUBSTRING_INDEX(SUBSTRING_INDEX(color, ',', 1), '(', -1);
        SET g_val = SUBSTRING_INDEX(SUBSTRING_INDEX(color, ',', 2), ',', -1);
        SET b_val = SUBSTRING_INDEX(SUBSTRING_INDEX(color, ')', 1), ',', -1);
        SET result = CONCAT('0x', LPAD(HEX(r_val), 2, '0'), LPAD(HEX(g_val), 2, '0'), LPAD(HEX(b_val), 2, '0'));
    -- 处理 HSL 格式（简化转换，假设 s 和 l 为百分比）
    ELSEIF color LIKE 'hsl(%' THEN
        SET h_val = SUBSTRING_INDEX(SUBSTRING_INDEX(color, ',', 1), '(', -1);
        SET s_val = REPLACE(SUBSTRING_INDEX(SUBSTRING_INDEX(color, ',', 2), ',', -1), '%', '');
        SET l_val = REPLACE(SUBSTRING_INDEX(SUBSTRING_INDEX(color, ')', 1), ',', -1), '%', '');
        -- 简化：这里假设直接映射，实际需要完整 HSL 到 RGB 转换逻辑
        SET result = CONCAT('0x', LPAD(HEX(CAST(h_val AS INT)), 2, '0'), LPAD(HEX(CAST(s_val AS INT)), 2, '0'), LPAD(HEX(CAST(l_val AS INT)), 2, '0'));
    ELSE
        SET result = 'Invalid format';
    END IF;
    RETURN result;
END;

