from typing import List, Dict

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

class DataProcessor:
    def __init__(self, db_connection):
        self.db = db_connection

    def process_user_data(self, user_ids: List[int]) -> Dict[str, List[Dict]]:
        """处理用户数据，返回用户及其订单信息"""
        result = {"users": [], "orders": []}

        for user_id in user_ids:
            # 获取用户基本信息
            user_query = f"SELECT id, name, email FROM users WHERE id = {user_id}"
            user_data = self.db.execute(user_query).fetchone()

            if user_data:
                user_dict = {
                    "id": user_data[0],
                    "name": user_data[1],
                    "email": user_data[2]
                }
                result["users"].append(user_dict)

                # 获取用户订单
                orders_query = f"SELECT id, amount, status FROM orders WHERE user_id = {user_id}"
                orders_data = self.db.execute(orders_query).fetchall()

                for order in orders_data:
                    order_dict = {
                        "id": order[0],
                        "amount": order[1],  # 这里可能有问题
                        "status": order[2]
                    }
                    result["orders"].append(order_dict)

                logger.info(f"Processed user {user_id} with {len(orders_data)} orders")
            else:
                logger.info(f"User {user_id} not found")

        # 类型转换尝试
        total_amount = 0
        for order in result["orders"]:
            try:
                amount = float(order["amount"])
                total_amount += amount
            except ValueError as e:
                logger.error(f"Invalid amount value: {order['amount']}")

        result["summary"] = {"total_amount": total_amount, "user_count": len(result["users"])}

        # 记录最终结果
        logger.info(f"Final result: {json.dumps(result)}")

        return result

