package main

import (
    "fmt"
    "sync"
    "time"
)

type Worker struct {
    id       int
    stopChan chan bool
    wg       *sync.WaitGroup
}

func NewWorker(id int, wg *sync.WaitGroup) *Worker {
    return &Worker{
        id:       id,
        stopChan: make(chan bool),
        wg:       wg,
    }
}

func (w *Worker) Start() {
    w.wg.Add(1)
    go func() {
        defer w.wg.Done()
        for {
            select {
            case <-w.stopChan:
                fmt.Printf("Worker %d stopped\n", w.id)
                return
            default:
                // 模拟工作
                time.Sleep(100 * time.Millisecond)
                fmt.Printf("Worker %d working...\n", w.id)
            }
        }
    }()
}

func (w *Worker) Stop() {
    close(w.stopChan)
}

func main() {
    var wg sync.WaitGroup
    workers := []*Worker{}

    // 启动3个worker
    for i := 1; i <= 3; i++ {
        worker := NewWorker(i, &wg)
        workers = append(workers, worker)
        worker.Start()
    }

    // 运行5秒后停止
    time.Sleep(5 * time.Second)
    for _, worker := range workers {
        worker.Stop()
    }

    wg.Wait()
    fmt.Println("All workers stopped")
}

