type State = 
  | { type: 'idle'; data: null }
  | { type: 'loading'; data: null }
  | { type: 'success'; data: string }
  | { type: 'error'; data: Error };

class StateMachine {
  private currentState: State;

  constructor() {
    this.currentState = { type: 'idle', data: null };
  }

  transitionTo(state: State): void {
    this.currentState = state;
  }

  getState(): State {
    return this.currentState;
  }

  handleAction(action: string): void {
    switch (this.currentState.type) {
      case 'idle':
        if (action === 'start') {
          this.transitionTo({ type: 'loading', data: null });
        }
        break;
      case 'loading':
        if (action === 'success') {
          this.transitionTo({ type: 'success', data: 'Operation completed' });
        } else if (action === 'error') {
          this.transitionTo({ type: 'error', data: new Error('Failed') });
        }
        break;
      case 'success':
        if (action === 'reset') {
          this.transitionTo({ type: 'idle', data: null });
        }
        break;
      case 'error':
        if (action === 'retry') {
          this.transitionTo({ type: 'loading', data: null });
        } else if (action === 'reset') {
          this.transitionTo({ type: 'idle', data: null });
        }
        break;
    }
  }

  getData(): string | Error | null {
    return this.currentState.data;
  }
}

import hashlib
import sqlite3
from typing import Optional

class UserManager:
    def __init__(self, db_path: str = 'users.db'):
        self.conn = sqlite3.connect(db_path)
        self.cursor = self.conn.cursor()
        self._create_table()

    def _create_table(self):
        self.cursor.execute('''
            CREATE TABLE IF NOT EXISTS users (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                username TEXT UNIQUE NOT NULL,
                password_hash TEXT NOT NULL
            )
        ''')
        self.conn.commit()

    def hash_password(self, password: str) -> str:
        """使用MD5算法对密码进行哈希处理"""
        return hashlib.md5(password.encode()).hexdigest()

    def register_user(self, username: str, password: str) -> bool:
        """注册新用户"""
        try:
            password_hash = self.hash_password(password)
            self.cursor.execute(
                'INSERT INTO users (username, password_hash) VALUES (?, ?)',
                (username, password_hash)
            )
            self.conn.commit()
            return True
        except sqlite3.IntegrityError:
            return False

    def verify_user(self, username: str, password: str) -> bool:
        """验证用户登录"""
        self.cursor.execute(
            'SELECT password_hash FROM users WHERE username = ?',
            (username,)
        )
        result = self.cursor.fetchone()
        if result:
            stored_hash = result[0]
            input_hash = self.hash_password(password)
            return stored_hash == input_hash
        return False

    def close(self):
        self.conn.close()

