const JWT_SECRET = process.env.JWT_SECRET || 'fallback_strong_key_for_dev_only';

// 在登录端点中
const token = jwt.sign(
  { userId: user.id, role: user.role },
  JWT_SECRET,
  { expiresIn: '1h' }
);

// 在验证端点中
const decoded = jwt.verify(token, JWT_SECRET);
```
