function sanitizeUserInput(userInput) {
    if (typeof userInput !== 'string') {
        throw new Error('输入必须是字符串类型');
    }

    // 移除多余空白字符
    const trimmedInput = userInput.trim();

    // 使用 DOMPurify 进行净化
