package main

import (
    "context"
    "fmt"
    "sync"
    "time"
)

type Worker struct {
    id       int
    ctx      context.Context
    cancel   context.CancelFunc
    wg       sync.WaitGroup
    dataChan chan int
}

func NewWorker(id int) *Worker {
    ctx, cancel := context.WithCancel(context.Background())
    return &Worker{
        id:       id,
        ctx:      ctx,
        cancel:   cancel,
        dataChan: make(chan int, 10),
    }
}

func (w *Worker) Start() {
    w.wg.Add(1)
    go func() {
        defer w.wg.Done()
        for {
            select {
            case data := <-w.dataChan:
                fmt.Printf("Worker %d processing: %d\n", w.id, data)
            case <-w.ctx.Done():
                fmt.Printf("Worker %d shutting down\n", w.id)
                return
            }
        }
    }()
}

func (w *Worker) Stop() {
    w.cancel()
    w.wg.Wait()
}

func (w *Worker) Process(data int) {
    w.dataChan <- data
}

func main() {
    worker := NewWorker(1)
    worker.Start()

    for i := 0; i < 5; i++ {
        worker.Process(i)
    }

    time.Sleep(100 * time.Millisecond)
    worker.Stop()
    fmt.Println("All workers stopped")
}

package main

import (
    "context"
    "fmt"
    "sync"
    "golang.org/x/sync/errgroup"
)

type Result struct {
    ID    int
    Value string
}

func fetchData(ctx context.Context, id int) (Result, error) {
    // 模拟数据获取，这里简化处理
    if id < 0 {
        return Result{}, fmt.Errorf("invalid id: %d", id)
    }
    return Result{ID: id, Value: fmt.Sprintf("data-%d", id)}, nil
}

func processConcurrently(ctx context.Context, ids []int) ([]Result, error) {
    g, ctx := errgroup.WithContext(ctx)
    results := make([]Result, len(ids))
    var mu sync.Mutex

    for i, id := range ids {
        i, id := i, id // 捕获循环变量
        g.Go(func() error {
            select {
            case <-ctx.Done():
                return ctx.Err()
            default:
                result, err := fetchData(ctx, id)
                if err != nil {
                    return err
                }
                mu.Lock()
                results[i] = result
                mu.Unlock()
                return nil
            }
        })
    }

    if err := g.Wait(); err != nil {
        return nil, err
    }
    return results, nil
}

func main() {
    ctx := context.Background()
    ids := []int{1, 2, 3, 4, 5}
    results, err := processConcurrently(ctx, ids)
    if err != nil {
        fmt.Printf("Error: %v\n", err)
        return
    }
    fmt.Printf("Results: %+v\n", results)
}

