import java.util.HashMap;
import java.util.Map;

public class UserCacheService {
    private static Map<String, String> userCache = new HashMap<>();
    private static Connection connection;

    static {
        try {
            connection = DriverManager.getConnection("jdbc:mysql://localhost:3306/test", "root", "password");
        } catch (SQLException e) {
            e.printStackTrace();
        }
    }

    public static String getUserInfo(String userId) {
        // 线程不安全：多个线程可能同时修改userCache
        if (userCache.containsKey(userId)) {
            return userCache.get(userId);
        }

        String userInfo = null;
        PreparedStatement stmt = null;
        ResultSet rs = null;
        try {
            // 空指针风险：userId可能为null
            stmt = connection.prepareStatement("SELECT info FROM users WHERE id = ?");
            stmt.setString(1, userId);
            rs = stmt.executeQuery();

            if (rs.next()) {
                userInfo = rs.getString("info");
                userCache.put(userId, userInfo);
            }
        } catch (SQLException e) {
            e.printStackTrace();
        } finally {
            // 资源泄漏：ResultSet和PreparedStatement未正确关闭
            try {
                if (rs != null) rs.close();
                if (stmt != null) stmt.close();
            } catch (SQLException e) {
                e.printStackTrace();
            }
        }

        return userInfo;
    }

    public static void clearCache() {
        userCache.clear();
    }

    public static void shutdown() {
        // 连接泄漏：静态Connection从未关闭
        // 应该在这里关闭connection
    }
}

