import java.util.HashMap;
import java.util.Map;

public class CommandLineParser {
    private Map<String, String> argsMap;
    private Map<String, Boolean> requiredArgs;

    public CommandLineParser(String[] args, Map<String, Boolean> requiredArgs) {
        this.requiredArgs = requiredArgs;
        argsMap = new HashMap<>();
        parseArgs(args);
        validateArgs();
    }

    private void parseArgs(String[] args) {
        for (int i = 0; i < args.length; i++) {
            if (args[i].startsWith("-")) {
                String key = args[i];
                String value = null;
                if (i + 1 < args.length && !args[i + 1].startsWith("-")) {
                    value = args[i + 1];
                    i++;
                }
                argsMap.put(key, value);
            } else {
                throw new IllegalArgumentException("Invalid argument format: " + args[i]);
            }
        }
    }

    private void validateArgs() {
        for (Map.Entry<String, Boolean> entry : requiredArgs.entrySet()) {
            String key = entry.getKey();
            boolean isRequired = entry.getValue();
            if (isRequired && !argsMap.containsKey(key)) {
                throw new IllegalArgumentException("Missing required argument: " + key);
            }
        }
    }

    public String getValue(String key) {
        return argsMap.get(key);
    }

    public static void main(String[] args) {
        Map<String, Boolean> requiredArgs = new HashMap<>();
        requiredArgs.put("-input", true);
        requiredArgs.put("-output", false); // output is optional

        try {
            CommandLineParser parser = new CommandLineParser(args, requiredArgs);
            String inputFile = parser.getValue("-input");
            String outputFile = parser.getValue("-output");
            System.out.println("Input file: " + inputFile);
            System.out.println("Output file: " + (outputFile != null ? outputFile : "default.txt"));
        } catch (IllegalArgumentException e) {
            System.err.println("Error: " + e.getMessage());
            System.exit(1);
        }
    }
}
```

### 最佳实践
1. **使用专门的库进行参数解析**：对于复杂的命令行应用，推荐使用 Apache Commons CLI 或 Picocli 等库，它们提供丰富的功能如类型转换、帮助生成和验证，减少自定义代码的错误。
2. **分离配置和业务逻辑**：将参数定义（如必需/可选、默认值）外部化到配置文件或常量类中，避免硬编码，提高代码的可维护性和测试性。

