type State = {
  type: 'idle';
  data: null;
} | {
  type: 'loading';
  data: null;
} | {
  type: 'success';
  data: string;
} | {
  type: 'error';
  data: Error;
};

class StateMachine {
  private currentState: State;

  constructor() {
    this.currentState = { type: 'idle', data: null };
  }

  transitionTo(state: State): void {
    this.currentState = state;
  }

  getCurrentState(): State {
    return this.currentState;
  }

  processData(): string | Error | null {
    switch (this.currentState.type) {
      case 'idle':
        return null;
      case 'loading':
        return null;
      case 'success':
        return this.currentState.data;
      case 'error':
        return this.currentState.data;
      default:
        const exhaustiveCheck: never = this.currentState;
        throw new Error(`Unexpected state: ${exhaustiveCheck}`);
    }
  }

  reset(): void {
    this.currentState = { type: 'idle', data: null };
  }
}

// 使用示例
const machine = new StateMachine();
machine.transitionTo({ type: 'loading', data: null });
machine.transitionTo({ type: 'success', data: 'Operation completed' });
console.log(machine.processData()); // 输出: 'Operation completed'

