import java.util.concurrent.atomic.AtomicInteger;

public class ConcurrentCounter {
    private volatile int count = 0;
    private final AtomicInteger atomicCount = new AtomicInteger(0);

    public void increment() {
        // 使用 volatile 确保可见性，但 increment 操作不是原子的
        count++;
        atomicCount.incrementAndGet();
    }

    public int getCount() {
        return count;
    }

    public int getAtomicCount() {
        return atomicCount.get();
    }

    public void reset() {
        // 单线程重置，无并发问题
        count = 0;
        atomicCount.set(0);
    }

    public static void main(String[] args) {
        ConcurrentCounter counter = new ConcurrentCounter();
        // 模拟单线程使用
        for (int i = 0; i < 1000; i++) {
            counter.increment();
        }
        System.out.println("Count: " + counter.getCount());
        System.out.println("Atomic Count: " + counter.getAtomicCount());
    }
}

type State = 
  | { type: 'idle'; data: null }
  | { type: 'loading'; data: null }
  | { type: 'success'; data: string }
  | { type: 'error'; data: Error };

class StateMachine {
  private currentState: State;

  constructor() {
    this.currentState = { type: 'idle', data: null };
  }

  transition(newState: State): void {
    this.currentState = newState;
  }

  getState(): State {
    return this.currentState;
  }

  handleAction(action: string): void {
    switch (this.currentState.type) {
      case 'idle':
        if (action === 'start') {
          this.transition({ type: 'loading', data: null });
        }
        break;
      case 'loading':
        if (action === 'success') {
          this.transition({ type: 'success', data: 'Operation completed' });
        } else if (action === 'error') {
          this.transition({ type: 'error', data: new Error('Failed') });
        }
        break;
      case 'success':
        if (action === 'reset') {
          this.transition({ type: 'idle', data: null });
        }
        break;
      case 'error':
        if (action === 'retry') {
          this.transition({ type: 'loading', data: null });
        }
        break;
    }
  }

  getData(): string | Error | null {
    return this.currentState.data;
  }
}

package main

import (
    "fmt"
    "sync"
    "time"
)

type Worker struct {
    id       int
    wg       *sync.WaitGroup
    stopChan chan struct{}
}

func NewWorker(id int, wg *sync.WaitGroup) *Worker {
    return &Worker{
        id:       id,
        wg:       wg,
        stopChan: make(chan struct{}),
    }
}

func (w *Worker) Start() {
    w.wg.Add(1)
    go func() {
        defer w.wg.Done()
        for {
            select {
            case <-w.stopChan:
                fmt.Printf("Worker %d stopped\n", w.id)
                return
            default:
                fmt.Printf("Worker %d working...\n", w.id)
                time.Sleep(500 * time.Millisecond)
            }
        }
    }()
}

func (w *Worker) Stop() {
    close(w.stopChan)
}

func main() {
    var wg sync.WaitGroup
    workers := make([]*Worker, 3)
    for i := 0; i < 3; i++ {
        workers[i] = NewWorker(i, &wg)
        workers[i].Start()
    }
    time.Sleep(2 * time.Second)
    for _, worker := range workers {
        worker.Stop()
    }
    wg.Wait()
    fmt.Println("All workers stopped")
}

