package main

import (
    "context"
    "errors"
    "fmt"
    "sync"
    "time"
    "golang.org/x/sync/errgroup"
)

func main() {
    ctx := context.Background()
    urls := []string{"https://api1.example.com", "https://api2.example.com", "https://api3.example.com"}

    results, err := fetchAll(ctx, urls)
    if err != nil {
        fmt.Printf("Error fetching data: %v\n", err)
        return
    }

    fmt.Printf("Successfully fetched %d results\n", len(results))
}

func fetchAll(ctx context.Context, urls []string) ([]string, error) {
    g, ctx := errgroup.WithContext(ctx)
    mu := sync.Mutex{}
    results := make([]string, 0, len(urls))

    for _, url := range urls {
        url := url
        g.Go(func() error {
            select {
            case <-ctx.Done():
                return ctx.Err()
            default:
                result, err := fetchURL(url)
                if err != nil {
                    return err
                }
                mu.Lock()
                results = append(results, result)
                mu.Unlock()
                return nil
            }
        })
    }

    if err := g.Wait(); err != nil {
        return nil, err
    }
    return results, nil
}

func fetchURL(url string) (string, error) {
    time.Sleep(100 * time.Millisecond)
    if url == "https://api2.example.com" {
        return "", errors.New("simulated error")
    }
    return fmt.Sprintf("data from %s", url), nil
}

