    mu      sync.Mutex
}

func (s *Service) ProcessRequest(reqID int) {
    // 竞态条件：counter 访问未加锁
    s.counter++
    fmt.Printf("Request %d processed, counter: %d\n", reqID, s.counter)

    // 错误吞咽：忽略可能的错误
    result, _ := s.doSomething()
    if result == nil {
        // panic 滥用：直接 panic 而不是优雅处理
