        try {
            Statement stmt = connection.createStatement();
            ResultSet rs = stmt.executeQuery(query);

            String userName = null;
            if (rs.next()) {
                userName = rs.getString("name");
            }

            userCache.put(userId, userName);
            return userName;
        } catch (SQLException e) {
            e.printStackTrace();
            return null;
        }
    }

