import java.util.concurrent.atomic.AtomicInteger;

public class CounterService {
    private volatile int counter = 0;
    private final AtomicInteger atomicCounter = new AtomicInteger(0);

    public void increment() {
        // 使用 volatile 确保可见性，但递增操作不是原子的
        counter++;
    }

    public int getCounter() {
        return counter;
    }

    public void safeIncrement() {
        // 使用 AtomicInteger 确保原子递增
        atomicCounter.incrementAndGet();
    }

    public int getSafeCounter() {
        return atomicCounter.get();
    }

    public void reset() {
        // 重置操作，单线程执行，无并发问题
        counter = 0;
        atomicCounter.set(0);
    }

    public static void main(String[] args) {
        CounterService service = new CounterService();
        // 模拟并发调用
        for (int i = 0; i < 10; i++) {
            new Thread(() -> {
                service.safeIncrement();
                service.increment();
            }).start();
        }
        // 等待线程完成
        try {
            Thread.sleep(1000);
        } catch (InterruptedException e) {
            e.printStackTrace();
        }
        System.out.println("Safe counter: " + service.getSafeCounter());
        System.out.println("Volatile counter: " + service.getCounter());
    }
}

