package main

import (
    "fmt"
    "net/http"
    "strconv"
    "sync"
    "time"
    "html"
)

type Message struct {
    ID        int
    SenderID  int
    ReceiverID int
    Content   string
    Timestamp time.Time
}

type MessageService struct {
    messages []Message
    mu       sync.Mutex
    nextID   int
}

func (ms *MessageService) SendMessage(senderID, receiverID int, content string) error {
    if len(content) > 1000 {
        return fmt.Errorf("content too long")
    }
    // 转义内容以防止 XSS
    escapedContent := html.EscapeString(content)
    ms.mu.Lock()
    defer ms.mu.Unlock()
    msg := Message{
        ID:        ms.nextID,
        SenderID:  senderID,
        ReceiverID: receiverID,
        Content:   escapedContent,
        Timestamp: time.Now(),
    }
    ms.messages = append(ms.messages, msg)
    ms.nextID++
    // 可选：限制消息存储，例如只保留最近 1000 条
    if len(ms.messages) > 1000 {
        ms.messages = ms.messages[1:]
    }
    return nil
}

func (ms *MessageService) GetMessages(userID int) []Message {
    ms.mu.Lock()
    defer ms.mu.Unlock()
    var userMessages []Message
    for _, msg := range ms.messages {
        if msg.ReceiverID == userID || msg.SenderID == userID {
            userMessages = append(userMessages, msg)
        }
    }
    return userMessages
}

func handleSendMessage(w http.ResponseWriter, r *http.Request) {
    if r.Method != "POST" {
        http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
        return
    }
    senderIDStr := r.FormValue("sender_id")
    receiverIDStr := r.FormValue("receiver_id")
    content := r.FormValue("content")
    if senderIDStr == "" || receiverIDStr == "" || content == "" {
        http.Error(w, "Missing parameters", http.StatusBadRequest)
        return
    }
    // 使用 strconv.Atoi 进行安全整数转换
    senderID, err := strconv.Atoi(senderIDStr)
    if err != nil {
        http.Error(w, "Invalid sender ID", http.StatusBadRequest)
        return
    }
    receiverID, err := strconv.Atoi(receiverIDStr)
    if err != nil {
        http.Error(w, "Invalid receiver ID", http.StatusBadRequest)
