type State = 
  | { type: 'idle'; data: null }
  | { type: 'loading'; data: null }
  | { type: 'success'; data: string }
  | { type: 'error'; data: string };

class StateMachine {
  private currentState: State;

  constructor(initialState: State) {
    this.currentState = initialState;
  }

  transition(newState: State): void {
    this.currentState = newState;
  }

  getState(): State {
    return this.currentState;
  }

  handleAction(action: string): void {
    switch (this.currentState.type) {
      case 'idle':
        if (action === 'start') {
          this.transition({ type: 'loading', data: null });
        }
        break;
      case 'loading':
        if (action === 'success') {
          this.transition({ type: 'success', data: 'Operation completed' });
        } else if (action === 'error') {
          this.transition({ type: 'error', data: 'Operation failed' });
        }
        break;
      case 'success':
        if (action === 'reset') {
          this.transition({ type: 'idle', data: null });
        }
        break;
      case 'error':
        if (action === 'retry') {
          this.transition({ type: 'loading', data: null });
        } else if (action === 'reset') {
          this.transition({ type: 'idle', data: null });
        }
        break;
    }
  }

  getData(): string | null {
    switch (this.currentState.type) {
      case 'success':
      case 'error':
        return this.currentState.data;
      default:
        return null;
    }
  }
}

