type State = 
  | { type: 'idle' }
  | { type: 'loading'; requestId: string }
  | { type: 'success'; data: string; timestamp: number }
  | { type: 'error'; message: string; code: number };

class StateMachine {
  private currentState: State;

  constructor(initialState: State = { type: 'idle' }) {
    this.currentState = initialState;
  }

  transition(newState: State): void {
    this.currentState = newState;
  }

  getState(): State {
    return this.currentState;
  }

  handleAction(action: string): void {
    switch (this.currentState.type) {
      case 'idle':
        if (action === 'start') {
          this.transition({ type: 'loading', requestId: 'req-' + Date.now() });
        }
        break;
      case 'loading':
        if (action === 'success') {
          this.transition({ type: 'success', data: 'Data loaded', timestamp: Date.now() });
        } else if (action === 'error') {
          this.transition({ type: 'error', message: 'Request failed', code: 500 });
        }
        break;
      case 'success':
        if (action === 'reset') {
          this.transition({ type: 'idle' });
        }
        break;
      case 'error':
        if (action === 'retry') {
          this.transition({ type: 'loading', requestId: 'req-' + Date.now() });
        } else if (action === 'reset') {
          this.transition({ type: 'idle' });
        }
        break;
    }
  }

  getStatus(): string {
    switch (this.currentState.type) {
      case 'idle':
        return 'Ready to start';
      case 'loading':
        return `Loading request ${this.currentState.requestId}`;
      case 'success':
        return `Data: ${this.currentState.data} at ${this.currentState.timestamp}`;
      case 'error':
        return `Error ${this.currentState.code}: ${this.currentState.message}`;
    }
  }
}

