import java.util.concurrent.atomic.AtomicInteger;

public class CounterService {
    private final AtomicInteger counter = new AtomicInteger(0);

    /**
     * 增加计数器值
     * @param delta 增加的值
     * @return 增加后的计数器值
     */
    public int increment(int delta) {
        return counter.addAndGet(delta);
    }

    /**
     * 获取当前计数器值
     * @return 当前计数器值
     */
    public int getValue() {
        return counter.get();
    }

    /**
     * 重置计数器
     */
    public void reset() {
        counter.set(0);
    }

    /**
     * 比较并设置计数器值
     * @param expect 期望值
     * @param update 更新值
     * @return 是否设置成功
     */
    public boolean compareAndSet(int expect, int update) {
        return counter.compareAndSet(expect, update);
    }

    /**
     * 示例使用
     */
    public static void main(String[] args) {
        CounterService service = new CounterService();

        // 模拟并发调用
        Thread t1 = new Thread(() -> {
            for (int i = 0; i < 1000; i++) {
                service.increment(1);
            }
        });

        Thread t2 = new Thread(() -> {
            for (int i = 0; i < 1000; i++) {
                service.increment(2);
            }
        });

        t1.start();
        t2.start();

        try {
            t1.join();
            t2.join();
        } catch (InterruptedException e) {
            e.printStackTrace();
        }

        System.out.println("Final counter value: " + service.getValue());
    }
}

package main

import (
    "fmt"
    "log"
    "net/http"
    "sync"
)

type Service struct {
    counter int
    mu      sync.Mutex
}

func (s *Service) handleRequest(w http.ResponseWriter, r *http.Request) {
    // 竞态条件：未加锁访问共享变量
    s.counter++
    fmt.Fprintf(w, "Counter: %d\n", s.counter)

    // 错误吞咽：忽略潜在错误
    data := make([]byte, 1024)
    _, _ = r.Body.Read(data) // 忽略读取错误

    // panic滥用：直接panic处理非致命错误
    if len(data) == 0 {
        panic("empty request body") // 应该返回错误而非panic
    }

    // 隐式竞态条件：并发写日志
    log.Printf("Request processed: %s", r.URL.Path)
}

func (s *Service) startServer() {
    http.HandleFunc("/", s.handleRequest)

    // 错误处理缺失：忽略服务器启动错误
    go func() {
        http.ListenAndServe(":8080", nil)
    }()

    // 隐式panic风险：未处理goroutine panic
    go s.backgroundTask()
}

func (s *Service) backgroundTask() {
    // 可能panic的操作
    var m map[string]string
    m["key"] = "value" // 空map赋值会panic
}

func main() {
    s := &Service{}
    s.startServer()
    select {} // 保持程序运行
}

