from dataclasses import dataclass, field
from typing import ClassVar, Optional
import hashlib

@dataclass(frozen=True, slots=True)
class ImmutableUser:
    """不可变用户值对象，使用 slots 优化内存和性能。"""

    username: str
    email: str
    age: int
    is_active: bool = field(default=True)
    _id: Optional[str] = field(default=None, init=False, repr=False)

    # 类变量，用于缓存哈希值以提高性能
    _hash_cache: ClassVar[dict] = {}

    def __post_init__(self):
        """验证数据并生成唯一 ID。"""
        if not isinstance(self.username, str) or len(self.username) < 3:
            raise ValueError("用户名必须为至少3个字符的字符串")
        if not isinstance(self.email, str) or '@' not in self.email:
            raise ValueError("邮箱格式无效")
        if not isinstance(self.age, int) or self.age < 0:
            raise ValueError("年龄必须为非负整数")

        # 生成基于内容的唯一 ID，确保不可变性
        content = f"{self.username}:{self.email}:{self.age}:{self.is_active}"
        object.__setattr__(self, '_id', hashlib.sha256(content.encode()).hexdigest())

    @property
    def id(self) -> str:
        """返回唯一 ID，确保安全访问。"""
        return self._id

    def __hash__(self) -> int:
        """重写哈希方法，使用缓存提高性能。"""
        if self._id not in self._hash_cache:
            self._hash_cache[self._id] = hash(self._id)
        return self._hash_cache[self._id]

    def __eq__(self, other) -> bool:
        """基于 ID 的相等性比较，确保一致性。"""
        if not isinstance(other, ImmutableUser):
            return False
        return self._id == other._id

    def to_dict(self) -> dict:
        """转换为字典，用于序列化。"""
        return {
            'username': self.username,
            'email': self.email,
            'age': self.age,
            'is_active': self.is_active,
            'id': self._id
        }

