import java.io.*;
import java.util.Base64;

public class DataProcessor {
    private static final String DATA_FILE = "data.bin";

    public static void main(String[] args) {
        try {
            // 从外部接收Base64编码的序列化数据
            String encodedData = args.length > 0 ? args[0] : readFromFile();

            // 解码并反序列化
            byte[] data = Base64.getDecoder().decode(encodedData);
            ByteArrayInputStream bis = new ByteArrayInputStream(data);
            ObjectInputStream ois = new ObjectInputStream(bis);

            // 反序列化对象
            Object obj = ois.readObject();
            ois.close();

            // 处理对象
            processObject(obj);

            System.out.println("数据处理完成");
        } catch (Exception e) {
            System.err.println("处理数据时出错: " + e.getMessage());
        }
    }

    private static String readFromFile() throws IOException {
        BufferedReader reader = new BufferedReader(new FileReader(DATA_FILE));
        String line = reader.readLine();
        reader.close();
        return line != null ? line : "";
    }

    private static void processObject(Object obj) {
        // 模拟对象处理逻辑
        System.out.println("处理对象: " + obj.getClass().getName());
    }
}

